SELECT * FROM sys_operation_log


        AND user_id = #{userId}


        AND module = #{module}


        AND operation = #{operation}


ORDER BY create_time DESC

SELECT l.*, u.real_name AS user_name FROM sys_operation_log l LEFT JOIN sys_user u ON l.user_id = u.pk_user
AND l.user_id = #{userId}
AND l.module LIKE CONCAT('%', #{module}, '%')
AND l.operation LIKE CONCAT('%', #{operation}, '%')
ORDER BY l.create_time DESC LIMIT #{offset}, #{pageSize}
